class Heart {
  constructor(x, y, size) {
    this.x = x;
    this.y = y;
    this.size = size;
    this.color = color(255, 0, 0); // Red
  }

  update() {
    this.x += random(-0.01, 0.01);
    this.y += random(-0.01, 0.01);
  }

